// MIT License//// Copyright (c) 2025-2026 Example Corp. All Rights Reserved.//// Licensed under the MIT License. See LICENSE file for details.using System;using System.Collections.Generic;using System.Linq;using Example.Application.OrderHeader.Models.Response;using Example.Domain.Entities;namespace Example.Application.Mapping.OrderHeader{    /// <summary>    /// Manual mapper implementation replacing AutoMapper profiles.    /// Provides explicit control over property mapping for OrderHeader entities.    /// </summary>    public class OrderHeaderMapper : IOrderHeaderMapper    {        private readonly Dictionary<string, Func<OrderHeaderOrderInfoEntity, object>> _customMappings;        public OrderHeaderMapper()        {            _customMappings = new Dictionary<string, Func<OrderHeaderOrderInfoEntity, object>>();        }        public OrderHeaderOrderInfoResponse MapOrderInfo(OrderHeaderOrderInfoEntity entity)        {            ArgumentNullException.ThrowIfNull(entity, nameof(entity));            return new OrderHeaderOrderInfoResponse            {                OrderId = entity.OrderIdentifier,                Status = entity.OrderStatus,                Priority = entity.OrderPriority,                CreatedDate = entity.CreatedDateUtc,                ModifiedDate = entity.ModifiedDateUtc,                Description = entity.OrderDescription,                Category = entity.OrderCategory,                Tags = entity.Tags?.ToList() ?? new List<string>(),                IsActive = entity.IsActive,                AssignedTo = entity.AssignedUserId            };        }        public SmallHeaderOrderInfoResponse MapSmallHeaderOrderInfo(OrderHeaderOrderInfoEntity entity)        {            ArgumentNullException.ThrowIfNull(entity, nameof(entity));            return new SmallHeaderOrderInfoResponse            {                OrderId = entity.OrderIdentifier,                Status = entity.OrderStatus,                Priority = entity.OrderPriority            };        }        public void RegisterCustomMapping(string key, Func<OrderHeaderOrderInfoEntity, object> mapping)        {            _customMappings[key] = mapping ?? throw new ArgumentNullException(nameof(mapping));        }        public object ApplyCustomMapping(string key, OrderHeaderOrderInfoEntity entity)        {            if (!_customMappings.TryGetValue(key, out var mapping))                throw new InvalidOperationException($"No custom mapping registered for key: {key}");            return mapping(entity);        }    }}